import{_ as s,c as t,o as n,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"快速开始: 5 分钟上手 | Plannotator","description":"学习 Plannotator 的安装和配置方法。在 5 分钟内完成 CLI 安装，配置 Claude Code 或 OpenCode 插件，掌握计划评审和代码评审流程。","frontmatter":{"title":"快速开始: 5 分钟上手 | Plannotator","sidebarTitle":"5 分钟上手","subtitle":"快速开始：5分钟上手 Plannotator","description":"学习 Plannotator 的安装和配置方法。在 5 分钟内完成 CLI 安装，配置 Claude Code 或 OpenCode 插件，掌握计划评审和代码评审流程。","tags":["快速开始","入门","安装","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"zh/backnotprop/plannotator/start/getting-started/index.md","filePath":"zh/backnotprop/plannotator/start/getting-started/index.md"}'),o={name:"zh/backnotprop/plannotator/start/getting-started/index.md"};function l(i,a,p,r,d,c){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="快速开始-5分钟上手-plannotator" tabindex="-1">快速开始：5分钟上手 Plannotator <a class="header-anchor" href="#快速开始-5分钟上手-plannotator" aria-label="Permalink to &quot;快速开始：5分钟上手 Plannotator&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>✅ 了解 Plannotator 的核心功能和使用场景</li><li>✅ 在 5 分钟内完成 Plannotator 安装</li><li>✅ 配置 Claude Code 或 OpenCode 集成</li><li>✅ 完成首次计划评审和代码评审</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p><strong>Plannotator</strong> 是一个为 Claude Code 和 OpenCode 设计的交互式评审工具，可以帮你解决以下问题：</p><p><strong>痛点 1</strong>：AI 生成的实施计划在终端里阅读，文字量大、结构不清晰，评审起来很累。</p><p><strong>痛点 2</strong>：想给 AI 反馈时，只能用文字描述&quot;删除第3段&quot;、&quot;修改这个函数&quot;，沟通成本高。</p><p><strong>痛点 3</strong>：代码评审时，需要打开多个终端或 IDE，来回切换，难以集中注意力。</p><p><strong>痛点 4</strong>：团队成员想参与评审，但不知道如何共享计划内容。</p><p><strong>Plannotator 能帮你</strong>：</p><ul><li>可视化 UI 替代终端阅读，结构清晰</li><li>选中文本即可添加注释（删除、替换、评论），精确反馈</li><li>Git diff 可视化评审，支持行级注释</li><li>URL 分享功能，无需后端即可团队协作</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p><strong>使用场景</strong>：</p><ul><li>使用 Claude Code 或 OpenCode 进行 AI 辅助开发</li><li>需要评审 AI 生成的实施计划</li><li>需要审查代码变更</li><li>需要与团队成员共享计划或代码评审结果</li></ul><p><strong>不适用场景</strong>：</p><ul><li>纯手工编写代码（不涉及 AI 生成计划）</li><li>已经有完整的代码审查流程（如 GitHub PR）</li><li>不需要可视化评审工具</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="plannotator-是什么" tabindex="-1">Plannotator 是什么 <a class="header-anchor" href="#plannotator-是什么" aria-label="Permalink to &quot;Plannotator 是什么&quot;">​</a></h3><p><strong>Plannotator</strong> 是一个为 AI Coding Agent（Claude Code、OpenCode）设计的交互式评审工具，主要提供两大功能：</p><ol><li><strong>计划评审</strong>：可视化评审 AI 生成的实施计划，支持添加注释、批准或拒绝</li><li><strong>代码评审</strong>：可视化评审 Git diff，支持行级注释和多种视图模式</li></ol><h3 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (生成计划)    │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← 本地 HTTP 服务器</span></span>
<span class="line"><span>│  (可视化 UI)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  浏览器        │</span></span>
<span class="line"><span>│  (用户评审)    │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>核心流程</strong>：</p><ol><li>AI Agent 完成计划或代码变更</li><li>Plannotator 在本地启动 HTTP 服务器，打开浏览器</li><li>用户在浏览器中查看计划/代码，添加注释</li><li>用户批准或拒绝，Plannotator 将决策返回给 AI Agent</li><li>AI Agent 根据反馈继续实施或修改</li></ol><h3 id="安全性" tabindex="-1">安全性 <a class="header-anchor" href="#安全性" aria-label="Permalink to &quot;安全性&quot;">​</a></h3><p><strong>所有数据本地处理</strong>，不会上传到云端：</p><ul><li>计划内容、代码 diff、注释都存储在你的本地机器</li><li>本地 HTTP 服务器使用随机端口（或固定端口）</li><li>URL 分享功能通过压缩数据到 URL hash 中实现，无需后端</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p><strong>系统要求</strong>：</p><ul><li>操作系统：macOS / Linux / Windows / WSL</li><li>运行时：Bun（安装脚本会自动处理）</li><li>AI 环境：Claude Code 2.1.7+ 或 OpenCode</li></ul><p><strong>安装方式选择</strong>：</p><ul><li>如果使用 Claude Code：需要安装 CLI + 插件</li><li>如果使用 OpenCode：需要配置插件</li><li>如果只做代码评审：只需安装 CLI</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-安装-plannotator-cli" tabindex="-1">第 1 步：安装 Plannotator CLI <a class="header-anchor" href="#第-1-步-安装-plannotator-cli" aria-label="Permalink to &quot;第 1 步：安装 Plannotator CLI&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>：</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>你应该看到</strong>：安装脚本会自动下载 Plannotator CLI 并将其添加到系统路径中，并显示版本号（如 &quot;plannotator v0.6.7 installed to ...&quot;）。</p><div class="tip custom-block"><p class="custom-block-title">安装脚本做了什么？</p><p>安装脚本会：</p><ol><li>下载最新版本的 Plannotator CLI</li><li>添加到系统路径（PATH）</li><li>清理可能存在的旧版本</li><li>自动安装 <code>/plannotator-review</code> 命令（用于代码评审）</li></ol></div><h3 id="第-2-步-配置-claude-code-可选" tabindex="-1">第 2 步：配置 Claude Code（可选） <a class="header-anchor" href="#第-2-步-配置-claude-code-可选" aria-label="Permalink to &quot;第 2 步：配置 Claude Code（可选）&quot;">​</a></h3><p>如果你使用 Claude Code，需要安装插件。</p><p><strong>在 Claude Code 中运行</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>重要</strong>：安装插件后，<strong>必须重启 Claude Code</strong> 才能让 hook 生效。</p><p><strong>你应该看到</strong>：插件安装成功后，Claude Code 的插件列表中会出现 <code>plannotator</code>。</p><div class="info custom-block"><p class="custom-block-title">手动配置方式（可选）</p><p>如果你不想使用插件系统，可以手动配置 hook。详见 <a href="./../installation-claude-code/">Claude Code 插件安装</a> 章节。</p></div><h3 id="第-3-步-配置-opencode-可选" tabindex="-1">第 3 步：配置 OpenCode（可选） <a class="header-anchor" href="#第-3-步-配置-opencode-可选" aria-label="Permalink to &quot;第 3 步：配置 OpenCode（可选）&quot;">​</a></h3><p>如果你使用 OpenCode，需要编辑 <code>opencode.json</code> 文件。</p><p><strong>编辑 <code>opencode.json</code></strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>重启 OpenCode</strong>。</p><p><strong>你应该看到</strong>：重启后，OpenCode 会自动加载插件，<code>submit_plan</code> 工具将可用。</p><h3 id="第-4-步-首次计划评审-claude-code-示例" tabindex="-1">第 4 步：首次计划评审（Claude Code 示例） <a class="header-anchor" href="#第-4-步-首次计划评审-claude-code-示例" aria-label="Permalink to &quot;第 4 步：首次计划评审（Claude Code 示例）&quot;">​</a></h3><p><strong>触发条件</strong>：让 Claude Code 生成一个实施计划，并调用 <code>ExitPlanMode</code>。</p><p><strong>示例对话</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：帮我写一个用户认证模块的实施计划</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude：好的，这是实施计划：</span></span>
<span class="line"><span>1. 创建用户模型</span></span>
<span class="line"><span>2. 实现注册 API</span></span>
<span class="line"><span>3. 实现登录 API</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（调用 ExitPlanMode）</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ol><li>浏览器自动打开 Plannotator UI</li><li>显示 AI 生成的计划内容</li><li>可以选中计划文本，添加注释（删除、替换、评论）</li><li>底部有&quot;Approve&quot;和&quot;Request Changes&quot;按钮</li></ol><p><strong>操作</strong>：</p><ol><li>浏览器查看计划</li><li>如果计划没问题，点击 <strong>Approve</strong> → AI 继续实施</li><li>如果需要修改，选中要改的文本，点击 <strong>Delete</strong>、<strong>Replace</strong> 或 <strong>Comment</strong> → 点击 <strong>Request Changes</strong></li></ol><p><strong>你应该看到</strong>：点击后，浏览器会自动关闭，Claude Code 会收到你的决策并继续执行。</p><h3 id="第-5-步-首次代码评审" tabindex="-1">第 5 步：首次代码评审 <a class="header-anchor" href="#第-5-步-首次代码评审" aria-label="Permalink to &quot;第 5 步：首次代码评审&quot;">​</a></h3><p><strong>在项目目录中运行</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ol><li>浏览器打开代码评审页面</li><li>显示 Git diff（默认是未提交的变更）</li><li>左侧是文件树，右侧是 diff viewer</li><li>点击行号可以选中代码范围，添加注释</li></ol><p><strong>操作</strong>：</p><ol><li>在 diff viewer 中浏览代码变更</li><li>点击行号选择要评审的代码</li><li>在右侧面板添加注释（comment/suggestion/concern）</li><li>点击 <strong>Send Feedback</strong> 发送给 agent，或点击 <strong>LGTM</strong> 批准</li></ol><p><strong>你应该看到</strong>：点击 Send Feedback 后，浏览器会关闭，终端中会输出格式化的反馈内容，agent 会自动处理。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成以上步骤后，你应该能够：</p><ul><li>[ ] 安装脚本显示 &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] 在 Claude Code 中触发计划评审，浏览器自动打开 UI</li><li>[ ] 在 UI 中选中计划文本，添加注释</li><li>[ ] 点击 Approve 或 Request Changes，看到浏览器关闭</li><li>[ ] 运行 <code>/plannotator-review</code>，看到代码评审界面</li><li>[ ] 在代码评审中添加行级注释，点击 Send Feedback</li></ul><p><strong>如果某一步失败</strong>，详见：</p><ul><li><a href="./../installation-claude-code/">Claude Code 安装指南</a></li><li><a href="./../installation-opencode/">OpenCode 安装指南</a></li><li><a href="./../../faq/common-problems/">常见问题</a></li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><p><strong>常见错误 1</strong>：安装后运行 <code>plannotator</code> 提示&quot;command not found&quot;</p><p><strong>原因</strong>：PATH 环境变量未更新，或需要重启终端。</p><p><strong>解决</strong>：</p><ul><li>macOS/Linux：运行 <code>source ~/.zshrc</code> 或 <code>source ~/.bashrc</code>，或重启终端</li><li>Windows：重启 PowerShell 或 CMD</li></ul><p><strong>常见错误 2</strong>：Claude Code 安装插件后，计划评审没有触发</p><p><strong>原因</strong>：未重启 Claude Code，hook 未生效。</p><p><strong>解决</strong>：完全退出 Claude Code（不只是关闭窗口），然后重新打开。</p><p><strong>常见错误 3</strong>：浏览器没有自动打开</p><p><strong>原因</strong>：可能是远程模式（如 devcontainer、SSH），或者端口被占用。</p><p><strong>解决</strong>：</p><ul><li>检查是否设置了 <code>PLANNOTATOR_REMOTE=1</code> 环境变量</li><li>查看终端输出的 URL，手动在浏览器中打开</li><li>详见 <a href="./../../advanced/remote-mode/">远程/Devcontainer 模式</a></li></ul><p><strong>常见错误 4</strong>：代码评审显示&quot;No changes&quot;</p><p><strong>原因</strong>：当前没有未提交的 git 变更。</p><p><strong>解决</strong>：</p><ul><li>先运行 <code>git status</code> 确认有变更</li><li>或运行 <code>git add</code> 暂存一些文件</li><li>或切换到其他 diff 类型（如 last commit）</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Plannotator 是一个本地运行的评审工具，通过可视化 UI 提升计划评审和代码评审的效率：</p><p><strong>核心功能</strong>：</p><ul><li><strong>计划评审</strong>：可视化评审 AI 生成的计划，支持精确注释</li><li><strong>代码评审</strong>：可视化评审 Git diff，支持行级注释</li><li><strong>URL 分享</strong>：无需后端即可分享评审内容</li><li><strong>第三方集成</strong>：自动保存批准的计划到 Obsidian/Bear</li></ul><p><strong>核心优势</strong>：</p><ul><li>本地运行，数据安全</li><li>可视化 UI，提升效率</li><li>精确反馈，减少沟通成本</li><li>团队协作，无需账号系统</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../installation-claude-code/">Claude Code 插件安装</a></strong>。</p><p>你会学到：</p><ul><li>详细的 Claude Code 插件安装步骤</li><li>手动配置 hook 的方法</li><li>如何验证安装是否成功</li><li>常见安装问题的解决方法</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>CLI 入口（计划评审）</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>CLI 入口（代码评审）</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>计划评审服务器</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>代码评审服务器</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Git 工具</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>计划评审 UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>代码评审 UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>MAX_RETRIES = 5</code>：端口重试次数（<code>packages/server/index.ts:80</code>）</li><li><code>RETRY_DELAY_MS = 500</code>：端口重试延迟（<code>packages/server/index.ts:80</code>）</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>startPlannotatorServer()</code>：启动计划评审服务器（<code>packages/server/index.ts</code>）</li><li><code>startReviewServer()</code>：启动代码评审服务器（<code>packages/server/review.ts</code>）</li><li><code>runGitDiff()</code>：运行 git diff 命令（<code>packages/server/git.ts</code>）</li></ul><p><strong>环境变量</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE</code>：远程模式标志（<code>apps/hook/server/index.ts:17</code>）</li><li><code>PLANNOTATOR_PORT</code>：固定端口（<code>apps/hook/server/index.ts:18</code>）</li><li><code>PLANNOTATOR_BROWSER</code>：自定义浏览器（<code>apps/hook/README.md:79</code>）</li><li><code>PLANNOTATOR_SHARE</code>：URL 分享开关（<code>apps/hook/server/index.ts:44</code>）</li></ul></details>`,104)])])}const u=s(o,[["render",l]]);export{g as __pageData,u as default};
